namespace {

class BoUpSLP;

/// A helper class for computing and caching profitability of vectorization
/// of a sequence of instructions.
class BottomUpSLPProfitabilityModel {
public:
  BottomUpSLPProfitabilityModel(BoUpSLP &V) : V(V) {}

  /// \returns true if it is profitable to vectorize the tree.
  bool isProfitable(const TreeEntry &TE);

private:
  BoUpSLP &V;
};

/// Bottom-up SLP vectorizer.
class BoUpSLP {
public:
  BoUpSLP(Function *F, ScalarEvolution *SE, TargetTransformInfo *TTI,
          TargetLibraryInfo *TLI, AAResults *AA, LoopInfo *LI,
          DominatorTree *DT, AssumptionCache *AC, DemandedBits *DB,
          const DataLayout *DL, OptimizationRemarkEmitter *ORE,
          MemorySSA *MSSA)
      : F(F), SE(SE), TTI(TTI), TLI(TLI), AA(AA), LI(LI), DT(DT), AC(AC),
        DB(DB), DL(DL), ORE(ORE), Builder(F->getContext()), MSSA(MSSA),
        ProfitabilityModel(*this) {}

  /// Vectorize the function.
  bool vectorize();

  /// Vectorize a single basic block.
  bool vectorize(BasicBlock *BB);

  /// \returns the vector representation of the instruction \p I.
  Value *getVectorValue(Instruction *I) const {
    return VectorizedValues.lookup(I);
  }

  /// \returns the scalar representation of the instruction \p I.
  Value *getScalarValue(Instruction *I) const {
    return ScalarValues.lookup(I);
  }

  /// \returns the vector representation of the value \p V.
  Value *getVectorValue(Value *V) const {
    if (auto *I = dyn_cast<Instruction>(V))
      return getVectorValue(I);
